import java.io.*;

public class InsecureDeserializationExample {

    public static void main(String[] args) {
        try {
            String userInput = "serialized_object_here"; // User-supplied serialized object

            // Deserialize the user input
            ByteArrayInputStream byteArrayInputStream = new ByteArrayInputStream(userInput.getBytes());
            ObjectInputStream objectInputStream = new ObjectInputStream(byteArrayInputStream);
            Object deserializedObject = objectInputStream.readObject();

            // Perform some operation with the deserialized object (e.g., casting it to a known class)
            if (deserializedObject instanceof String) {
                String str = (String) deserializedObject;
                System.out.println("Deserialized string: " + str);
            }

        } catch (IOException | ClassNotFoundException e) {
            e.printStackTrace();
        }
    }
}

